import { useState } from "react";
import "./Borrow.css";

export default function LibraryApp() {
  const [title, setTitle] = useState("");
  const [author, setAuthor] = useState("");
  const [description, setDescription] = useState("");
  const [publishedYear, setPublishedYear] = useState("");
  const [books, setBooks] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [borrowedBooks, setBorrowedBooks] = useState([]);

  const addBook = () => {
    if (!title || !author || !description || !publishedYear) return;
    const newBook = { id: Date.now(), title, author, description, publishedYear };
    setBooks([...books, newBook]);
    setTitle("");
    setAuthor("");
    setDescription("");
    setPublishedYear("");
  };

  const borrowBook = (book) => {
    setBorrowedBooks([...borrowedBooks, book]);
  };

  const filteredBooks = books.filter((book) =>
    book.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    book.author.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="library-container">
      <h1 className="library-title">Library Management</h1>
      
      <div className="book-form">
        <input className="library-input" placeholder="Title" value={title} onChange={(e) => setTitle(e.target.value)} />
        <input className="library-input" placeholder="Author" value={author} onChange={(e) => setAuthor(e.target.value)} />
        <input className="library-input" placeholder="Description" value={description} onChange={(e) => setDescription(e.target.value)} />
        <input className="library-input" placeholder="Published Year" value={publishedYear} onChange={(e) => setPublishedYear(e.target.value)} />
        <button className="library-button" onClick={addBook}>Add Book</button>
      </div>

      <input
        className="library-input"
        placeholder="Search by Title or Author"
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
      />

      <h2 className="library-subtitle">Available Books</h2>
      {filteredBooks.length === 0 ? (
        <p className="empty-message">No books found</p>
      ) : (
        <ul className="book-list">
          {filteredBooks.map((book) => (
            <li key={book.id} className="book-item">
              <strong>{book.title} <span>by {book.author}</span></strong>
              <button className="borrow-button" onClick={() => borrowBook(book)}>Borrow</button>
            </li>
          ))}
        </ul>
      )}

      <h2 className="library-subtitle">Borrowed Books</h2>
      {borrowedBooks.length === 0 ? (
        <p className="empty-message">No books borrowed</p>
      ) : (
        <ul className="book-list">
          {borrowedBooks.map((book, index) => (
            <li key={index} className="book-item">
              <strong>{book.title} <span>by {book.author}</span></strong>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
